-- Enrichment marathon batch: Nutshell, Nuxt, NymphCast, OBS Studio, Observium, Obsidian, Ocoya, October CMS

-- ── Nutshell ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nutshell is a cloud-based CRM and revenue platform that combines sales pipeline management, email marketing automation, and customer engagement tools built for small and midsize B2B sales teams.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$13/user/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Ann Arbor, Michigan, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nutshell CRM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nutshell CRM review 2026: pricing plans, pipeline and marketing automation features, pros and cons, and the best alternatives for small business sales teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nutshell is a cloud-based customer relationship management (CRM) and revenue platform built for small and midsize B2B sales and marketing teams. The company was founded in Ann Arbor, Michigan in 2010 by Andy Fowler, Guy Suter, and Ian Berry, and publicly launched at the Future of Web Design conference that same year. In October 2022, Nutshell was acquired by WebFX, a digital marketing agency, and now operates alongside sibling products SEO.com and TeamAI as part of the WebFX family of companies, while remaining headquartered in Ann Arbor with additional offices in New York, Cape Town, and Sydney. Nutshell serves more than 5,000 companies across roughly 50 countries, positioning itself as an easier-to-use, more affordable alternative to enterprise CRMs like Salesforce, while offering more built-in marketing capability than lightweight pipeline tools like Pipedrive. Its core differentiator is combining sales CRM, email marketing automation, and sales engagement (sequences, click-to-call, email tracking) into a single platform rather than requiring separate tools, plus multiple pipeline visualizations including board (Kanban), list, chart, and a map view that plots deals and contacts geographically. Nutshell IQ, its AI layer, generates deal summaries, meeting recaps, and sales coaching insights from call and email data. Pricing is per-user, per-month, billed annually, spanning five tiers: Foundation at $13, Growth at $25, Pro at $42, Business at $59, and Enterprise at $79, with monthly billing available at higher rates. Optional add-ons extend the platform further: Marketing Pro ($49 per company per month) adds email marketing automation and drip sequences, Engagement Pro ($16 per user per month) adds sales engagement and sequencing tools, and Nutshell IQ ($37 per company per month for 100 credits) adds AI-generated insights. Nutshell integrates with QuickBooks, Google Workspace, Microsoft Outlook, Mailchimp, Intercom, Slack, and Zapier, and offers native iOS and Android apps. Its target audience is small and midsize B2B companies, particularly those without a dedicated CRM administrator, who want an all-in-one system a sales team can adopt without heavy customization or a long implementation cycle. Competitors most frequently cited alongside Nutshell include HubSpot, Pipedrive, Zoho CRM, Close, Keap, and Salesforce. Reviewers consistently highlight Nutshell's ease of onboarding, responsive customer support, and pipeline visualization as strengths, while noting that its reporting and customization depth lag behind larger enterprise CRM suites, and that some marketing and AI features require add-on purchases rather than being included at every tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'de6eb85c-e884-4464-97df-4e4c4479c1d0';

