-- ── NymphCast ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$NymphCast is a free, open-source audio and video casting system that turns Linux-capable hardware like a Raspberry Pi into a network media receiver, similar in concept to Chromecast.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$N/A (hobbyist open-source project, no company)$q$, company_size),
  headquarters = COALESCE($q$N/A (independent open-source project)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$NymphCast Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$NymphCast review 2026: what this open-source Raspberry Pi casting server can do, how it compares to Chromecast, and where to find setup docs and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$NymphCast is a free, open-source audio and video casting system created by developer Maya Posch (GitHub handle MayaPosch) and documented on the Nyanko project website. It turns Linux-capable single-board computers, most commonly the Raspberry Pi, into a network media receiver that can play audio and video streamed from client devices or from internet sources, conceptually similar to a self-hosted, hackable alternative to Google Chromecast. The project is released under a BSD license, with source code hosted publicly on GitHub, and it has no company, funding, or commercial entity behind it -- it is maintained as a hobbyist open-source project. NymphCast consists of a server component that runs on the receiving hardware and connects to a television or powered speakers, and client applications (including command-line and GUI clients, plus an Android app) that send media to the server over the local network. A distinguishing feature is support for NymphCast apps, small programs written in AngelScript that extend server functionality, for example adding support for additional third-party streaming protocols or building custom on-screen interfaces, though this apps system is still described as a preview-status feature by the project. Because it is entirely open source and self-hosted, NymphCast has no subscription fees, accounts, or vendor lock-in, and users are expected to build or flash the software themselves onto supported hardware. The project targets hobbyists, home-lab and DIY media-center builders, and embedded-systems enthusiasts who want a network casting receiver they fully control rather than a closed commercial device. Its closest points of comparison are Google Chromecast (proprietary, commercial) and other DIY or open-source casting and media-center projects such as Kodi with casting plugins; unlike those, NymphCast is positioned specifically as a lightweight, embeddable casting protocol and server rather than a full media-center UI. As with many single-maintainer open-source projects, documentation and release cadence can be inconsistent, and the project explicitly notes that some features remain experimental with bugs to be expected.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7bd17012-c4b3-4edc-a6fb-45ecafd92bb2';

