-- ── OBS Studio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OBS Studio is a free, open-source application for video recording and live streaming, offering scene composition, audio mixing, and an extensible plugin system used by streamers, educators, and broadcasters worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Volunteer-driven open-source community (OBS Project), no fixed employee count$q$, company_size),
  headquarters = COALESCE($q$N/A (distributed open-source project; OBS Project is a nonprofit community organization)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OBS Studio Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OBS Studio review 2026: features, plugin ecosystem, and pricing (it's free) for the world's most popular open-source streaming and recording software.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OBS Studio (Open Broadcaster Software Studio) is a free, open-source application for video recording and live streaming, maintained by the OBS Project, a community organization funded through Open Collective and Patreon rather than a traditional company. The software originated in August 2012 as Open Broadcaster Software, a single-developer Windows application created by Hugh 'Jim' Bailey so he could stream StarCraft; in 2013-2014 it was rewritten from scratch as a cross-platform application under the name OBS Multiplatform, later renamed OBS Studio, while the original codebase was retired as 'OBS Classic' in 2016. Since then it has grown into the de-facto standard for live streaming and screen recording, used by Twitch and YouTube streamers, educators, corporate broadcasters, and podcasters, competing with commercial and freemium tools such as Streamlabs (itself built on OBS's open-source code), XSplit, Restream Studio, and Ecamm Live. OBS Studio's core capabilities include unlimited scene composition combining game captures, webcams, browser sources, images, and text; an advanced audio mixer with per-source noise suppression, noise gates, and VST plugin support; and encoding output to RTMP, HLS, SRT, and WebRTC protocols with recording formats including MKV, MP4, MOV, FLV, and TS. A built-in virtual camera feature lets users pipe OBS scenes into Zoom, Microsoft Teams, or Google Meet as a webcam source. Because OBS Studio exposes a plugin API, a large third-party ecosystem has grown around it, including popular plugins for multi-platform RTMP output, automatic scene switching, and per-source recording, maintained by streaming companies and individual developers alike. The software runs on Windows, macOS, and Linux and receives regular version updates; as of 2026 it remains on an actively developed release cycle with contributions from a global community of volunteer developers. OBS Studio has no pricing tiers, licenses, watermarks, or paywalled features -- it is entirely free under an open-source license, with the OBS Project accepting optional donations to fund ongoing development. Its target audience spans hobbyist streamers with no budget for commercial software up through professional broadcast operations that build custom production pipelines on top of OBS's plugin architecture, making it one of the most widely adopted pieces of open-source software in the content creation and live-streaming space.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba63a23f-3cf0-4180-a7bf-2561af98bb09';

