-- ── Obsidian ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Obsidian is a free, local-first note-taking and personal knowledge management app that stores notes as plain Markdown files and supports deep customization through community plugins and a linked, graph-based structure.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~18 employees$q$, company_size),
  headquarters = COALESCE($q$Toronto, Ontario, Canada (fully remote team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Obsidian Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Obsidian review 2026: features, pricing (free core app plus paid Sync and Publish), pros, cons, and the best alternatives for note-taking and PKM.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Obsidian is a free, local-first note-taking and personal knowledge management (PKM) application that stores every note as a plain Markdown text file on the user's own device rather than in a proprietary cloud database. It was created in 2020 by co-founders Shida Li and Erica Xu, who met at the University of Waterloo and had previously built the outliner app Dynalist; Erica started building Obsidian during COVID-19 lockdowns to create what the team calls 'the perfect note-taking app' for her own notes, drawing inspiration from and addressing shortcomings in tools like TiddlyWiki and MediaWiki. The company is headquartered in Toronto, Canada, operates as a fully remote, distributed team of roughly 18 people, and is explicitly user-funded rather than venture-backed, describing itself as '100% supported by our users, not investors.' Steph Ango (also known online as @kepano) became CEO in February 2023. Obsidian's core differentiator is its local-first, file-over-app philosophy: notes live as durable .md files in a folder on the user's computer, ensuring longevity and preventing vendor lock-in, while the app's bidirectional linking, backlinks panel, and interactive graph view let users build a densely connected 'second brain' of notes. The application itself is free for both personal and commercial use, with the commercial license restriction removed entirely in 2025. Obsidian generates revenue through optional paid services layered on top of the free core app: Obsidian Sync (end-to-end encrypted note synchronization across devices, priced around $4 to $5 per month) and Obsidian Publish (for turning a vault into a public website), plus a Catalyst one-time payment tier that grants early access to beta builds and supports development. The app is highly extensible through a large community plugin and theme ecosystem, covering everything from task management and spaced-repetition flashcards to canvas-style visual note boards. Obsidian's target audience spans students, researchers, writers, developers, and knowledge workers who want a durable, private, and deeply customizable alternative to cloud note apps. Its most frequently cited competitors include Notion, Roam Research, Logseq (open source), Evernote, OneNote, and Apple Notes, with Obsidian generally positioned as the choice for users who prioritize data ownership, offline access, and plugin-driven customization over built-in collaboration or a polished out-of-the-box UI.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '45916754-f5bf-43e2-98ed-4d4cec40d20c';

